    })
    return unicodedata.normalize("NFKD", value).encode("ascii", "ignore").decode().translate(table)


def normalize_email(raw_email: str, errors: dict[str, list[str]]) -> str | None:
    email = normalize_text(raw_email)

    if not email:
        add_error(errors, "email", "required")
        return None

    if len(email) > 320:
        add_error(errors, "email", "too_long")

    if contains_control_or_bidi(email) or HTML_DANGEROUS_RE.search(email):
        add_error(errors, "email", "invalid_characters")

    try:
        result = validate_email(
            email,
            check_deliverability=False,
            allow_smtputf8=False,
        )
    except EmailNotValidError:
        add_error(errors, "email", "invalid_format")
        return None

    normalized = result.normalized.lower()
    local, domain = normalized.rsplit("@", 1)

    if len(local) > 64:
        add_error(errors, "email", "local_part_too_long")

    try:
        ascii_domain = idna.encode(domain, uts46=True).decode("ascii").lower()
    except idna.IDNAError:
        add_error(errors, "email", "invalid_domain")
        return None

    if ascii_domain in DISPOSABLE_DOMAINS:
        add_error(errors, "email", "disposable_email_not_allowed")

    if ascii_domain in {"localhost", "example.com", "invalid", "test"}:
        add_error(errors, "email", "reserved_domain_not_allowed")

    if "." not in ascii_domain:
        add_error(errors, "email", "domain_requires_public_suffix")

    try:
        answers = dns.resolver.resolve(ascii_domain, "MX", lifetime=2.0)
        if not answers:
            add_error(errors, "email", "domain_has_no_mx")
    except Exception:
        add_error(errors, "email", "domain_has_no_mx")

    return f"{local}@{ascii_domain}"


def validate_username(raw_username: str, errors: dict[str, list[str]]) -> str | None:
    username = normalize_text(raw_username).lower()

    if not username:
        add_error(errors, "username", "required")
        return None

    if len(username) < 3:
        add_error(errors, "username", "too_short")

    if len(username) > 30:
        add_error(errors, "username", "too_long")

    if contains_control_or_bidi(username):
        add_error(errors, "username", "invalid_unicode_controls")

    if not USERNAME_RE.fullmatch(username):
        add_error(errors, "username", "invalid_format")

    if username.startswith((".", "-", "_")) or username.endswith((".", "-", "_")):
        add_error(errors, "username", "invalid_edge_character")

    if ".." in username or "__" in username or "--" in username:
        add_error(errors, "username", "repeated_separator")

    if username in RESERVED_USERNAMES:
        add_error(errors, "username", "reserved")

    if any(word in username for word in OFFENSIVE_WORDS):
        add_error(errors, "username", "disallowed_content")

    if REPEATED_CHARS_RE.search(username):
        add_error(errors, "username", "excessive_repetition")

    if confusable_username_key(username) in RESERVED_USERNAMES:
        add_error(errors, "username", "confusable_reserved_name")

