    return password.lower() in COMMON_PASSWORDS


def validate_password(
    password: str,
    email: str | None,
    username: str | None,
    display_name: str | None,
    errors: dict[str, list[str]],
) -> str | None:
    if not password:
        add_error(errors, "password", "required")
        return None

    if not isinstance(password, str):
        add_error(errors, "password", "must_be_string")
        return None

    if len(password) < 12:
        add_error(errors, "password", "too_short")

    if len(password) > 256:
        add_error(errors, "password", "too_long")

    if len(password.encode("utf-8")) > BCRYPT_MAX_BYTES:
        add_error(errors, "password", "too_many_bytes_for_bcrypt")

    if contains_control_or_bidi(password):
        add_error(errors, "password", "invalid_unicode_controls")

    if password.strip() != password:
        add_error(errors, "password", "leading_or_trailing_whitespace")

    categories = {
        "lower": any(c.islower() for c in password),
        "upper": any(c.isupper() for c in password),
        "digit": any(c.isdigit() for c in password),
        "symbol": any(not c.isalnum() for c in password),
    }

    if sum(categories.values()) < 3:
        add_error(errors, "password", "insufficient_character_variety")

    if REPEATED_CHARS_RE.search(password):
        add_error(errors, "password", "excessive_repetition")

    lowered = password.lower()

    if password_breached(password):
        add_error(errors, "password", "known_weak_or_breached")

    if username and username in lowered:
        add_error(errors, "password", "too_similar_to_username")

    if email:
        local = email.split("@", 1)[0].lower()
        domain = email.split("@", 1)[1].split(".", 1)[0].lower()

        if local and local in lowered:
            add_error(errors, "password", "too_similar_to_email")

        if domain and domain in lowered:
            add_error(errors, "password", "too_similar_to_email_domain")

    if display_name:
        for part in display_name.lower().split():
            if len(part) >= 4 and part in lowered:
                add_error(errors, "password", "too_similar_to_display_name")
                break

    return password


