@app.post("/api/register")
async def register(payload: RegisterPayload, request: Request):
    errors: dict[str, list[str]] = {}

    ip = client_ip(request)
    if not ip_limiter.allow(ip):
        return JSONResponse(
            status_code=429,
            content={
                "status": "error",
                "errors": {"non_field_errors": ["rate_limited"]},
            },
            headers={"Retry-After": "60"},
        )

    for field in ("email", "username", "password", "display_name"):
        if not isinstance(getattr(payload, field), str):
            add_error(errors, field, "must_be_string")

    if errors:
        return JSONResponse(status_code=422, content={"status": "error", "errors": errors})

    email = normalize_email(payload.email, errors)
    username = validate_username(payload.username, errors)
    display_name = validate_display_name(payload.display_name, errors)
    password = validate_password(payload.password, email, username, display_name, errors)

    if email and not email_limiter.allow(hash_email(email)):
        return JSONResponse(
            status_code=429,
            content={
                "status": "error",
                "errors": {"non_field_errors": ["rate_limited"]},
            },
            headers={"Retry-After": "3600"},
        )

    if errors:
        return JSONResponse(status_code=422, content={"status": "error", "errors": errors})

    assert email is not None
    assert username is not None
    assert password is not None
    assert display_name is not None

    email_digest = hash_email(email)
    username_key = confusable_username_key(username)

    with db_session() as db:
        existing_email = db.execute(
            select(User.id).where(User.email_hash == email_digest)
        ).scalar_one_or_none()

        # Do not reveal whether the email is already registered.
        if existing_email is not None:
            bcrypt.hashpw(password.encode("utf-8"), bcrypt.gensalt(rounds=12))
            return generic_success()

        existing_username = db.execute(
            select(User.id).where(
                (User.username == username)
                | (User.username_confusable_key == username_key)
            )
        ).scalar_one_or_none()

        if existing_username is not None:
            return JSONResponse(
                status_code=409,
                content={
                    "status": "error",
                    "errors": {"username": ["unavailable"]},
                },
            )

        user = User(
            email_normalized=email,
            email_hash=email_digest,
            username=username,
            username_confusable_key=username_key,
            password_hash=hash_password(password),
            display_name=display_name,
            created_at=datetime.now(timezone.utc),
        )

        db.add(user)

        try:
            db.flush()
        except IntegrityError:
            # Handles concurrent signups against unique constraints.
            return generic_success()

    return generic_success()
